-- sampleDBB.sql
-- QCR / Quality Claim Response sample MySQL schema
-- Purpose:
--   - Store confirmed claim reports as reusable similar cases.
--   - Store text and structured report data in MySQL.
--   - Store images as files and keep only image paths in MySQL.
--   - Do not store PDF files as the primary case data.

CREATE DATABASE IF NOT EXISTS sampleDBB
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE sampleDBB;

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS defect_report_images;
DROP TABLE IF EXISTS defect_reports;
DROP TABLE IF EXISTS defect_types;

SET FOREIGN_KEY_CHECKS = 1;

-- Defect type master table.
CREATE TABLE defect_types (
    code        VARCHAR(30) PRIMARY KEY,
    label       VARCHAR(100) NOT NULL,
    category_id INT,
    description TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO defect_types (code, label, category_id, description) VALUES
('OUTER_DAMAGE', '외관 손상', 102, '외관 긁힘, 찍힘, 변형 등 육안 식별 불량'),
('SEALING',      '실링 불량', 204, '실링재 미도포, 부족, 위치 이탈, 들뜸'),
('HEMMING',      '헤밍 불량', 212, '헤밍 공정 접합 불량, 압착 불량, 벌어짐'),
('HOLE_DEFORM',  '홀 변형',   213, '홀 치수 이탈, 위치 이탈, 변형');

-- Main report table.
-- One approved row in this table is treated as one reusable similar case.
CREATE TABLE defect_reports (
    report_id BIGINT AUTO_INCREMENT PRIMARY KEY,

    -- Document / workflow information
    document_no VARCHAR(50) NOT NULL UNIQUE,
    received_date DATE NOT NULL DEFAULT (CURRENT_DATE),
    completed_at DATETIME,

    -- Defect information
    defect_type VARCHAR(30) NOT NULL,
    defect_code VARCHAR(50),
    defect_location VARCHAR(255),

    -- Customer / product / process information
    customer_name VARCHAR(100) NOT NULL,
    product_name VARCHAR(100) NOT NULL,
    product_no VARCHAR(100),
    part_name VARCHAR(100),
    process_name VARCHAR(100),
    lot_no VARCHAR(100),

    -- Quantity information
    delivery_quantity INT NOT NULL DEFAULT 0,

    -- Text data for LLM parsing and similar-case reasoning
    claim_text LONGTEXT,
    extracted_text LONGTEXT,
    claim_summary TEXT,
    image_caption TEXT,

    -- Analysis and actions
    root_cause_analysis TEXT,
    corrective_action TEXT,
    preventive_action TEXT,

    -- People
    handler VARCHAR(50),
    author_name VARCHAR(50),
    reviewer_name VARCHAR(50),
    approver_name VARCHAR(50),

    -- Status
    report_status ENUM('draft', 'reviewing', 'approved', 'archived') NOT NULL DEFAULT 'draft',

    CONSTRAINT fk_defect_reports_defect_type
        FOREIGN KEY (defect_type)
        REFERENCES defect_types(code),

    CONSTRAINT chk_defect_reports_delivery_quantity
        CHECK (delivery_quantity >= 0),

    INDEX idx_reports_status_type (report_status, defect_type),
    INDEX idx_reports_customer (customer_name),
    INDEX idx_reports_product (product_name, product_no),
    INDEX idx_reports_received_date (received_date),
    FULLTEXT INDEX ft_reports_text (
        claim_text,
        extracted_text,
        claim_summary,
        image_caption,
        root_cause_analysis,
        corrective_action,
        preventive_action
    )
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Report image table.
-- Actual image files are stored under application-managed upload folders.
-- MySQL stores only paths and descriptions.
CREATE TABLE defect_report_images (
    image_id BIGINT AUTO_INCREMENT PRIMARY KEY,
    report_id BIGINT NOT NULL,

    image_type ENUM('전체', '불량부위', '근접', '기타') NOT NULL DEFAULT '불량부위',
    image_path VARCHAR(500) NOT NULL,
    image_description VARCHAR(255),

    uploaded_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT fk_defect_report_images_report
        FOREIGN KEY (report_id)
        REFERENCES defect_reports(report_id)
        ON DELETE CASCADE,

    INDEX idx_images_report (report_id),
    INDEX idx_images_type (image_type)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Sample similar-case seed data.
