-- DBeaver quick verification queries.
-- Execute these after running the schema to confirm the structure.

SELECT 'defect_types' AS table_name, COUNT(*) AS row_count FROM defect_types;

SELECT
    table_name,
    engine,
    table_collation
FROM information_schema.tables
WHERE table_schema = 'sampleDBB'
ORDER BY table_name;

SELECT
    table_name,
    column_name,
    data_type,
    is_nullable
FROM information_schema.columns
WHERE table_schema = 'sampleDBB'
ORDER BY table_name, ordinal_position;

SELECT
    constraint_name,
    table_name,
    referenced_table_name
FROM information_schema.referential_constraints
WHERE constraint_schema = 'sampleDBB'
ORDER BY table_name, constraint_name;

